// Bookmark Manager API — entrypoint
// See PRODUCT_SPEC.md for full requirements
// The agent will build this out across tasks T1-T6

import express from "express";
import Database from "better-sqlite3";

const app = express();
const PORT = process.env.PORT || 3000;
const db: Database.Database = new Database("data.db");

app.use(express.json());

db.pragma("foreign_keys = ON");

db.exec(`
  CREATE TABLE IF NOT EXISTS folders (
    id INTEGER PRIMARY KEY,
    name TEXT NOT NULL,
    created_at TEXT NOT NULL,
    updated_at TEXT NOT NULL
  )
`);

db.exec(`
  CREATE TABLE IF NOT EXISTS bookmarks (
    id INTEGER PRIMARY KEY,
    url TEXT NOT NULL,
    title TEXT NOT NULL,
    description TEXT,
    folder_id INTEGER REFERENCES folders(id) ON DELETE SET NULL,
    created_at TEXT NOT NULL,
    updated_at TEXT NOT NULL
  )
`);

const bookmarkColumns = db
  .prepare("PRAGMA table_info(bookmarks)")
  .all() as Array<{ name: string }>;

if (!bookmarkColumns.some((column) => column.name === "folder_id")) {
  db.exec(
    "ALTER TABLE bookmarks ADD COLUMN folder_id INTEGER REFERENCES folders(id) ON DELETE SET NULL",
  );
}

type Bookmark = {
  id: number;
  url: string;
  title: string;
  description: string | null;
  folder_id: number | null;
  created_at: string;
  updated_at: string;
};

type Folder = {
  id: number;
  name: string;
  created_at: string;
  updated_at: string;
};

const selectBookmarkById = db.prepare<[number], Bookmark>(
  "SELECT id, url, title, description, folder_id, created_at, updated_at FROM bookmarks WHERE id = ?",
);

const selectFolderById = db.prepare<[number], Folder>(
  "SELECT id, name, created_at, updated_at FROM folders WHERE id = ?",
);

const isNonEmptyString = (value: unknown): value is string =>
  typeof value === "string" && value.trim().length > 0;

const parseId = (value: string): number | null => {
  const id = Number(value);
  return Number.isInteger(id) && id > 0 ? id : null;
};

const parseOptionalFolderId = (value: unknown): number | null | undefined => {
  if (value === undefined) {
    return undefined;
  }

  if (value === null) {
    return null;
  }

  return typeof value === "number" && Number.isInteger(value) && value > 0
    ? value
    : null;
};

const folderExists = (id: number): boolean => Boolean(selectFolderById.get(id));

app.get("/health", (_req, res) => {
  res.status(200).json({ status: "ok" });
});

app.post("/folders", (req, res) => {
  const { name } = req.body;

  if (!isNonEmptyString(name)) {
    return res.status(400).json({ error: "name is required" });
  }

  const now = new Date().toISOString();
  const result = db
    .prepare(
      `
        INSERT INTO folders (name, created_at, updated_at)
        VALUES (?, ?, ?)
      `,
    )
    .run(name.trim(), now, now);

  const folder = selectFolderById.get(Number(result.lastInsertRowid));
  return res.status(201).json(folder);
});

app.get("/folders", (_req, res) => {
  const folders = db
    .prepare<[], Folder>(
      "SELECT id, name, created_at, updated_at FROM folders ORDER BY id ASC",
    )
    .all();

  return res.status(200).json(folders);
});

app.get("/folders/:id", (req, res) => {
  const id = parseId(req.params.id);

  if (id === null) {
    return res.status(404).json({ error: "folder not found" });
  }

  const folder = selectFolderById.get(id);

  if (!folder) {
    return res.status(404).json({ error: "folder not found" });
  }

  const bookmarks = db
    .prepare<[number], Bookmark>(
      `
        SELECT id, url, title, description, folder_id, created_at, updated_at
        FROM bookmarks
        WHERE folder_id = ?
        ORDER BY id ASC
      `,
    )
    .all(id);

  return res.status(200).json({ ...folder, bookmarks });
});

app.put("/folders/:id", (req, res) => {
  const id = parseId(req.params.id);

  if (id === null) {
    return res.status(404).json({ error: "folder not found" });
  }

  const folder = selectFolderById.get(id);

  if (!folder) {
    return res.status(404).json({ error: "folder not found" });
  }

  const { name } = req.body;

  if (!isNonEmptyString(name)) {
    return res.status(400).json({ error: "name must be non-empty" });
  }

  db.prepare(
    `
      UPDATE folders
      SET name = ?, updated_at = ?
      WHERE id = ?
    `,
  ).run(name.trim(), new Date().toISOString(), id);

  return res.status(200).json(selectFolderById.get(id));
});

app.delete("/folders/:id", (req, res) => {
  const id = parseId(req.params.id);

  if (id === null) {
    return res.status(404).json({ error: "folder not found" });
  }

  const result = db.transaction((folderId: number) => {
    const folder = selectFolderById.get(folderId);

    if (!folder) {
      return { deleted: false };
    }

    db.prepare(
      "UPDATE bookmarks SET folder_id = NULL, updated_at = ? WHERE folder_id = ?",
    ).run(new Date().toISOString(), folderId);
    db.prepare("DELETE FROM folders WHERE id = ?").run(folderId);

    return { deleted: true };
  })(id);

  if (!result.deleted) {
    return res.status(404).json({ error: "folder not found" });
  }

  return res.status(204).send();
});

app.post("/bookmarks", (req, res) => {
  const { url, title, description, folder_id } = req.body;

  if (!isNonEmptyString(url)) {
    return res.status(400).json({ error: "url is required" });
  }

  if (!isNonEmptyString(title)) {
    return res.status(400).json({ error: "title is required" });
  }

  const parsedFolderId = parseOptionalFolderId(folder_id);

  if (parsedFolderId === null && folder_id !== null) {
    return res
      .status(400)
      .json({ error: "folder_id must be a positive integer" });
  }

  if (typeof parsedFolderId === "number" && !folderExists(parsedFolderId)) {
    return res
      .status(400)
      .json({ error: "folder_id does not reference an existing folder" });
  }

  const now = new Date().toISOString();
  const result = db
    .prepare(
      `
        INSERT INTO bookmarks (url, title, description, folder_id, created_at, updated_at)
        VALUES (?, ?, ?, ?, ?, ?)
      `,
    )
    .run(
      url.trim(),
      title.trim(),
      typeof description === "string" ? description : null,
      parsedFolderId ?? null,
      now,
      now,
    );

  const bookmark = selectBookmarkById.get(Number(result.lastInsertRowid));
  return res.status(201).json(bookmark);

});

app.get("/bookmarks", (_req, res) => {
  const bookmarks = db
    .prepare<[], Bookmark>(
      "SELECT id, url, title, description, folder_id, created_at, updated_at FROM bookmarks ORDER BY id ASC",
    )
    .all();

  return res.status(200).json(bookmarks);
});

app.get("/bookmarks/:id", (req, res) => {
  const id = parseId(req.params.id);

  if (id === null) {
    return res.status(404).json({ error: "bookmark not found" });
  }

  const bookmark = selectBookmarkById.get(id);

  if (!bookmark) {
    return res.status(404).json({ error: "bookmark not found" });
  }

  return res.status(200).json(bookmark);
});

app.put("/bookmarks/:id", (req, res) => {
  const id = parseId(req.params.id);

  if (id === null) {
    return res.status(404).json({ error: "bookmark not found" });
  }

  const bookmark = selectBookmarkById.get(id);

  if (!bookmark) {
    return res.status(404).json({ error: "bookmark not found" });
  }

  const { url, title, description, folder_id } = req.body;

  if (url !== undefined && !isNonEmptyString(url)) {
    return res.status(400).json({ error: "url must be non-empty" });
  }

  if (title !== undefined && !isNonEmptyString(title)) {
    return res.status(400).json({ error: "title must be non-empty" });
  }

  const parsedFolderId = parseOptionalFolderId(folder_id);

  if (parsedFolderId === null && folder_id !== null) {
    return res
      .status(400)
      .json({ error: "folder_id must be a positive integer" });
  }

  if (typeof parsedFolderId === "number" && !folderExists(parsedFolderId)) {
    return res
      .status(400)
      .json({ error: "folder_id does not reference an existing folder" });
  }

  const updated = {
    url: url === undefined ? bookmark.url : url.trim(),
    title: title === undefined ? bookmark.title : title.trim(),
    description:
      description === undefined
        ? bookmark.description
        : typeof description === "string"
          ? description
          : null,
    folder_id: folder_id === undefined ? bookmark.folder_id : parsedFolderId,
    updated_at: new Date().toISOString(),
  };

  db.prepare(
    `
      UPDATE bookmarks
      SET url = ?, title = ?, description = ?, folder_id = ?, updated_at = ?
      WHERE id = ?
    `,
  ).run(
    updated.url,
    updated.title,
    updated.description,
    updated.folder_id,
    updated.updated_at,
    id,
  );

  return res.status(200).json(selectBookmarkById.get(id));
});

app.delete("/bookmarks/:id", (req, res) => {
  const id = parseId(req.params.id);

  if (id === null) {
    return res.status(404).json({ error: "bookmark not found" });
  }

  const result = db.prepare("DELETE FROM bookmarks WHERE id = ?").run(id);

  if (result.changes === 0) {
    return res.status(404).json({ error: "bookmark not found" });
  }

  return res.status(204).send();
});

app.listen(PORT, () => {
  console.log(`Server running on port ${PORT}`);
});

export default app;
export { db };
